69	func NewService(pool *pgxpool.Pool, auditSvc *audit.Service, exportsDir string) *Service {
70		return &Service{pool: pool, auditSvc: auditSvc, exportsDir: exportsDir}
71	}
72	
73	func (s *Service) CreateNotification(ctx context.Context, nType, title, body, entityType string, entityID int, recipientUserIDs []int) error {
74		tx, err := s.pool.Begin(ctx)
75		if err != nil {
76			return err
77		}
78		defer tx.Rollback(ctx)
79	
80		var notifID int
81		err = tx.QueryRow(ctx, `INSERT INTO notifications (type, title, body, entity_type, entity_id) VALUES ($1,$2,$3,$4,$5) RETURNING id`,
82			nType, title, body, entityType, entityID).Scan(&notifID)
83		if err != nil {
84			return err
85		}
86	
87		for _, uid := range recipientUserIDs {
88			tx.Exec(ctx, `INSERT INTO notification_recipients (notification_id, user_id) VALUES ($1, $2)`, notifID, uid)
89		}
90	
91		return tx.Commit(ctx)
92	}
93	
94	func (s *Service) ListForUser(ctx context.Context, userID int) ([]Notification, error) {
95		rows, err := s.pool.Query(ctx, `SELECT n.id, n.type, n.title, COALESCE(n.body,''), COALESCE(n.entity_type,''), COALESCE(n.entity_id,0), nr.is_read, n.created_at
96			FROM notifications n JOIN notification_recipients nr ON nr.notification_id = n.id
97			WHERE nr.user_id = $1 ORDER BY n.created_at DESC LIMIT 100`, userID)
98		if err != nil {
99			return nil, err
100		}
101		defer rows.Close()
102	
103		var notifs []Notification
104		for rows.Next() {
105			var n Notification
106			if err := rows.Scan(&n.ID, &n.Type, &n.Title, &n.Body, &n.EntityType, &n.EntityID, &n.IsRead, &n.CreatedAt); err != nil {
107				return nil, err
108			}
109			notifs = append(notifs, n)
110		}
111		return notifs, nil
112	}
