131	func (s *Service) ListAnnouncements(ctx context.Context, userID int) ([]Announcement, error) {
132		rows, err := s.pool.Query(ctx, `SELECT a.id, a.title, a.body, a.priority, a.is_active,
133			CASE WHEN ar.user_id IS NOT NULL THEN TRUE ELSE FALSE END,
134			a.created_at
135			FROM announcements a
136			LEFT JOIN announcement_reads ar ON ar.announcement_id = a.id AND ar.user_id = $1
137			WHERE a.is_active=TRUE AND (a.expires_at IS NULL OR a.expires_at > NOW())
138			ORDER BY a.created_at DESC`, userID)
139		if err != nil {
140			return nil, err
141		}
142		defer rows.Close()
143	
144		var anns []Announcement
145		for rows.Next() {
146			var a Announcement
147			if err := rows.Scan(&a.ID, &a.Title, &a.Body, &a.Priority, &a.IsActive, &a.IsRead, &a.CreatedAt); err != nil {
148				return nil, err
149			}
150			anns = append(anns, a)
151		}
152		return anns, nil
153	}
