162	func (s *Service) GetPreferences(ctx context.Context, userID int) ([]Preference, error) {
163		rows, err := s.pool.Query(ctx, `SELECT channel, event_type, enabled FROM notification_preferences WHERE user_id=$1`, userID)
164		if err != nil {
165			return nil, err
166		}
167		defer rows.Close()
168	
169		var prefs []Preference
170		for rows.Next() {
171			var p Preference
172			if err := rows.Scan(&p.Channel, &p.EventType, &p.Enabled); err != nil {
173				return nil, err
174			}
175			prefs = append(prefs, p)
176		}
177		return prefs, nil
178	}
