180	func (s *Service) UpdatePreferences(ctx context.Context, userID int, prefs []Preference) error {
181		if len(prefs) == 0 {
182			return fmt.Errorf("cannot update with empty preference list")
183		}
184	
185		// Capture before state for audit
186		before, _ := s.GetPreferences(ctx, userID)
187	
188		tx, err := s.pool.Begin(ctx)
189		if err != nil {
190			return err
191		}
192		defer tx.Rollback(ctx)
193	
194		tx.Exec(ctx, `DELETE FROM notification_preferences WHERE user_id=$1`, userID)
195		for _, p := range prefs {
196			tx.Exec(ctx, `INSERT INTO notification_preferences (user_id, channel, event_type, enabled) VALUES ($1,$2,$3,$4)`,
197				userID, p.Channel, p.EventType, p.Enabled)
198		}
199	
200		s.auditSvc.LogTx(ctx, tx, audit.LogParams{
201			EntityType:  "notification_preference",
202			EntityID:    userID,
203			Action:      "updated",
204			ActorUserID: &userID,
205			Before:      before,
206			After:       prefs,
207		})
208	
209		return tx.Commit(ctx)
210	}
