212	func (s *Service) ListExportQueue(ctx context.Context) ([]ExportQueueItem, error) {
213		rows, err := s.pool.Query(ctx, `SELECT id, channel, recipient, COALESCE(subject,''), body, status, attempts, max_attempts, created_at
214			FROM export_queue_items ORDER BY created_at DESC LIMIT 100`)
215		if err != nil {
216			return nil, err
217		}
218		defer rows.Close()
219	
220		var items []ExportQueueItem
221		for rows.Next() {
222			var item ExportQueueItem
223			if err := rows.Scan(&item.ID, &item.Channel, &item.Recipient, &item.Subject, &item.Body, &item.Status, &item.Attempts, &item.MaxAttempts, &item.CreatedAt); err != nil {
