236	
237	func (s *Service) ProcessExportRetries(ctx context.Context) (int, error) {
238		rows, err := s.pool.Query(ctx, `SELECT id, channel, recipient, subject, body, attempts, max_attempts FROM export_queue_items
239			WHERE status IN ('pending','retrying') AND attempts < max_attempts`)
240		if err != nil {
241			return 0, err
242		}
243		defer rows.Close()
244	
245		count := 0
246		for rows.Next() {
247			var item ExportQueueItem
248			if err := rows.Scan(&item.ID, &item.Channel, &item.Recipient, &item.Subject, &item.Body, &item.Attempts, &item.MaxAttempts); err != nil {
249				continue
250			}
251	
252			newAttempt := item.Attempts + 1
253	
254			// Write actual local artifact file
255			filename := fmt.Sprintf("export_%d_%s_%d.txt", item.ID, item.Channel, newAttempt)
256			exportPath := filepath.Join(s.exportsDir, filename)
257			payload := fmt.Sprintf("Channel: %s\nRecipient: %s\nSubject: %s\n\n%s", item.Channel, item.Recipient, item.Subject, item.Body)
258	
259			exportStatus := "exported"
260			if err := os.WriteFile(exportPath, []byte(payload), 0644); err != nil {
261				exportStatus = "retrying"
262				exportPath = ""
263			}
264	
265			s.pool.Exec(ctx, `UPDATE export_queue_items SET status=$1, attempts=$2, last_attempt_at=NOW(), updated_at=NOW() WHERE id=$3`,
266				exportStatus, newAttempt, item.ID)
267			s.pool.Exec(ctx, `INSERT INTO export_attempt_logs (queue_item_id, attempt_number, status, exported_path) VALUES ($1,$2,$3,$4)`,
268				item.ID, newAttempt, exportStatus, exportPath)
269			if exportStatus == "exported" {
270				count++
271			}
272		}
273		return count, nil
274	}
275	
276	// RenderTemplate performs simple variable substitution in templates
277	func (s *Service) RenderTemplate(ctx context.Context, templateCode string, vars map[string]string) (string, string, error) {
278		var tmpl Template
279		err := s.pool.QueryRow(ctx, `SELECT id, code, name, subject, body FROM notification_templates WHERE code=$1`, templateCode).
280			Scan(&tmpl.ID, &tmpl.Code, &tmpl.Name, &tmpl.Subject, &tmpl.Body)
281		if err != nil {
282			return "", "", err
283		}
284	
285		subject := tmpl.Subject
286		body := tmpl.Body
287		for k, v := range vars {
288			subject = strings.ReplaceAll(subject, "{{"+k+"}}", v)
289			body = strings.ReplaceAll(body, "{{"+k+"}}", v)
290		}
291	
292		return subject, body, nil
293	}
