1	package imports
2	
3	import (
4		"context"
5		"encoding/csv"
6		"encoding/json"
7		"errors"
8		"fmt"
9		"io"
10		"strconv"
11		"time"
12	
13		"fleetcommerce/internal/audit"
14	
15		"github.com/jackc/pgx/v5/pgxpool"
16	)
17	
18	type ImportJob struct {
19		ID            int       `json:"id"`
20		Filename      string    `json:"filename"`
21		Status        string    `json:"status"`
22		TotalRows     int       `json:"total_rows"`
23		ValidRows     int       `json:"valid_rows"`
24		InvalidRows   int       `json:"invalid_rows"`
25		CommittedRows int       `json:"committed_rows"`
26		UploadedBy    *int      `json:"uploaded_by"`
27		CreatedAt     time.Time `json:"created_at"`
28	}
29	
30	type ImportRow struct {
31		ID        int             `json:"id"`
32		JobID     int             `json:"job_id"`
33		RowNumber int             `json:"row_number"`
34		RawData   json.RawMessage `json:"raw_data"`
35		Status    string          `json:"status"`
36		Errors    json.RawMessage `json:"errors"`
37	}
38	
39	var requiredHeaders = []string{"model_code", "model_name", "brand", "series", "year"}
40	
41	type Service struct {
42		pool     *pgxpool.Pool
43		auditSvc *audit.Service
44	}
45	
46	func NewService(pool *pgxpool.Pool, auditSvc *audit.Service) *Service {
47		return &Service{pool: pool, auditSvc: auditSvc}
48	}
49	
50	func (s *Service) ParseAndValidate(ctx context.Context, filename string, reader io.Reader, uploadedBy int) (*ImportJob, []ImportRow, error) {
51		csvReader := csv.NewReader(reader)
52		headers, err := csvReader.Read()
53		if err != nil {
54			return nil, nil, fmt.Errorf("read headers: %w", err)
55		}
56	
57		headerMap := make(map[string]int)
58		for i, h := range headers {
59			headerMap[h] = i
60		}
61	
62		for _, req := range requiredHeaders {
63			if _, ok := headerMap[req]; !ok {
64				return nil, nil, fmt.Errorf("missing required column: %s", req)
65			}
66		}
67	
68		// Create job
69		var jobID int
70		err = s.pool.QueryRow(ctx, `INSERT INTO csv_import_jobs (filename, uploaded_by) VALUES ($1, $2) RETURNING id`, filename, uploadedBy).Scan(&jobID)
71		if err != nil {
72			return nil, nil, err
73		}
74	
75		var rows []ImportRow
76		rowNum := 0
77		validCount := 0
78		invalidCount := 0
79	
80		for {
81			record, err := csvReader.Read()
82			if err == io.EOF {
83				break
84			}
85			if err != nil {
86				continue
87			}
88			rowNum++
89	
90			data := make(map[string]string)
91			for name, idx := range headerMap {
92				if idx < len(record) {
93					data[name] = record[idx]
94				}
95			}
96	
97			rawData, _ := json.Marshal(data)
98			rowErrors := s.validateRow(ctx, data, rowNum)
99	
100			status := "valid"
101			var errJSON json.RawMessage
102			if len(rowErrors) > 0 {
103				status = "invalid"
104				errJSON, _ = json.Marshal(rowErrors)
105				invalidCount++
106			} else {
107				validCount++
108			}
109	
110			var rowID int
111			s.pool.QueryRow(ctx, `INSERT INTO csv_import_rows (job_id, row_number, raw_data, status, errors) VALUES ($1,$2,$3,$4,$5) RETURNING id`,
112				jobID, rowNum, rawData, status, errJSON).Scan(&rowID)
113	
114			rows = append(rows, ImportRow{
115				ID:        rowID,
116				JobID:     jobID,
117				RowNumber: rowNum,
118				RawData:   rawData,
119				Status:    status,
120				Errors:    errJSON,
121			})
122		}
123	
124		// Update job counts
125		s.pool.Exec(ctx, `UPDATE csv_import_jobs SET total_rows=$1, valid_rows=$2, invalid_rows=$3, status='validated' WHERE id=$4`,
126			rowNum, validCount, invalidCount, jobID)
127	
128		job := &ImportJob{
129			ID:          jobID,
130			Filename:    filename,
131			Status:      "validated",
132			TotalRows:   rowNum,
133			ValidRows:   validCount,
134			InvalidRows: invalidCount,
135			UploadedBy:  &uploadedBy,
136		}
137	
138		return job, rows, nil
139	}
140	
141	func (s *Service) validateRow(ctx context.Context, data map[string]string, rowNum int) map[string]string {
142		errs := make(map[string]string)
143	
144		if data["model_code"] == "" {
145			errs["model_code"] = "Model code is required"
146		}
147		if data["model_name"] == "" {
148			errs["model_name"] = "Model name is required"
149		}
150		if data["brand"] == "" {
151			errs["brand"] = "Brand is required"
152		}
153		if data["series"] == "" {
154			errs["series"] = "Series is required"
155		}
156	
157		if yr := data["year"]; yr != "" {
158			y, err := strconv.Atoi(yr)
159			if err != nil || y < 1900 || y > 2100 {
160				errs["year"] = "Year must be between 1900 and 2100"
161			}
162		} else {
163			errs["year"] = "Year is required"
164		}
165	
166		if sq := data["stock_quantity"]; sq != "" {
167			if n, err := strconv.Atoi(sq); err != nil || n < 0 {
168				errs["stock_quantity"] = "Stock quantity must be a non-negative integer"
169			}
170		}
171	
172		if ps := data["publication_status"]; ps != "" {
173			validStatuses := map[string]bool{"draft": true, "published": true, "unpublished": true}
174			if !validStatuses[ps] {
175				errs["publication_status"] = "Invalid publication status"
176			}
177		}
178	
179		if ed := data["expiry_date"]; ed != "" {
180			if _, err := time.Parse("2006-01-02", ed); err != nil {
181				errs["expiry_date"] = "Invalid date format (expected YYYY-MM-DD)"
182			}
183		}
184	
185		// Check for duplicate model code
186		if data["model_code"] != "" {
187			var exists int
188			s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM vehicle_models WHERE model_code=$1`, data["model_code"]).Scan(&exists)
189			if exists > 0 {
190				errs["model_code"] = "Duplicate model code already exists in database"
191			}
192		}
193	
194		return errs
195	}
