197	func (s *Service) GetJob(ctx context.Context, jobID int) (*ImportJob, error) {
198		var job ImportJob
199		err := s.pool.QueryRow(ctx, `SELECT id, filename, status, total_rows, valid_rows, invalid_rows, committed_rows, uploaded_by, created_at FROM csv_import_jobs WHERE id=$1`, jobID).
200			Scan(&job.ID, &job.Filename, &job.Status, &job.TotalRows, &job.ValidRows, &job.InvalidRows, &job.CommittedRows, &job.UploadedBy, &job.CreatedAt)
201		if err != nil {
202			return nil, err
203		}
204		return &job, nil
205	}
