207	func (s *Service) GetJobRows(ctx context.Context, jobID int) ([]ImportRow, error) {
208		rows, err := s.pool.Query(ctx, `SELECT id, job_id, row_number, raw_data, status, errors FROM csv_import_rows WHERE job_id=$1 ORDER BY row_number`, jobID)
209		if err != nil {
210			return nil, err
211		}
212		defer rows.Close()
213	
214		var result []ImportRow
215		for rows.Next() {
216			var r ImportRow
217			if err := rows.Scan(&r.ID, &r.JobID, &r.RowNumber, &r.RawData, &r.Status, &r.Errors); err != nil {
218				return nil, err
219			}
220			result = append(result, r)
