225	func (s *Service) CommitJob(ctx context.Context, jobID int, actorID int) error {
226		job, err := s.GetJob(ctx, jobID)
227		if err != nil {
228			return err
229		}
230		if job.Status != "validated" {
231			return errors.New("job is not in validated state")
232		}
233	
234		// Load valid rows before starting transaction
235		validRows, err := s.pool.Query(ctx, `SELECT id, raw_data FROM csv_import_rows WHERE job_id=$1 AND status='valid'`, jobID)
236		if err != nil {
237			return err
238		}
239		type rowData struct {
240			ID   int
241			Data map[string]string
242		}
243		var rows []rowData
244		for validRows.Next() {
245			var id int
246			var raw json.RawMessage
247			if err := validRows.Scan(&id, &raw); err != nil {
248				validRows.Close()
249				return fmt.Errorf("scan row: %w", err)
250			}
251			var d map[string]string
252			json.Unmarshal(raw, &d)
253			rows = append(rows, rowData{ID: id, Data: d})
254		}
255		validRows.Close()
256	
257		// All-or-nothing transaction
258		tx, err := s.pool.Begin(ctx)
259		if err != nil {
260			return err
261		}
262		defer tx.Rollback(ctx)
263	
264		committed := 0
265		for _, row := range rows {
266			data := row.Data
267	
268			// Find or create brand
269			var brandID int
270			err := tx.QueryRow(ctx, `SELECT id FROM brands WHERE name=$1`, data["brand"]).Scan(&brandID)
271			if err != nil {
272				if err := tx.QueryRow(ctx, `INSERT INTO brands (name) VALUES ($1) ON CONFLICT (name) DO UPDATE SET name=EXCLUDED.name RETURNING id`, data["brand"]).Scan(&brandID); err != nil {
273					return fmt.Errorf("row %d: create brand: %w", row.ID, err)
274				}
275			}
276	
277			// Find or create series
278			var seriesID int
279			err = tx.QueryRow(ctx, `SELECT id FROM series WHERE brand_id=$1 AND name=$2`, brandID, data["series"]).Scan(&seriesID)
280			if err != nil {
281				if err := tx.QueryRow(ctx, `INSERT INTO series (brand_id, name) VALUES ($1, $2) ON CONFLICT (brand_id, name) DO UPDATE SET name=EXCLUDED.name RETURNING id`, brandID, data["series"]).Scan(&seriesID); err != nil {
282					return fmt.Errorf("row %d: create series: %w", row.ID, err)
283				}
284			}
285	
286			year, _ := strconv.Atoi(data["year"])
287			stock := 0
288			if sv, err := strconv.Atoi(data["stock_quantity"]); err == nil {
289				stock = sv
290			}
291			pubStatus := "draft"
292			if ps := data["publication_status"]; ps != "" {
293				pubStatus = ps
294			}
295	
296			if _, err := tx.Exec(ctx, `INSERT INTO vehicle_models (brand_id, series_id, model_code, model_name, year, description, publication_status, stock_quantity, expiry_date)
297				VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)`,
298				brandID, seriesID, data["model_code"], data["model_name"], year, data["description"], pubStatus, stock, nilIfEmpty(data["expiry_date"])); err != nil {
299				return fmt.Errorf("row %d: insert vehicle: %w", row.ID, err)
300			}
301	
302			if _, err := tx.Exec(ctx, `UPDATE csv_import_rows SET status='committed' WHERE id=$1`, row.ID); err != nil {
303				return fmt.Errorf("row %d: update status: %w", row.ID, err)
304			}
305			committed++
306		}
307	
308		if _, err := tx.Exec(ctx, `UPDATE csv_import_jobs SET status='committed', committed_rows=$1, completed_at=NOW() WHERE id=$2`, committed, jobID); err != nil {
309			return fmt.Errorf("update job: %w", err)
310		}
311	
312		if err := tx.Commit(ctx); err != nil {
313			// On commit failure, mark job as failed outside the rolled-back tx
314			s.pool.Exec(ctx, `UPDATE csv_import_jobs SET status='failed', completed_at=NOW() WHERE id=$1`, jobID)
315			return fmt.Errorf("commit: %w", err)
316		}
317	
318		s.auditSvc.Log(ctx, audit.LogParams{
319			EntityType: "csv_import", EntityID: jobID, Action: "committed", ActorUserID: &actorID,
320			Metadata: map[string]int{"committed_rows": committed},
321		})
322		return nil
323	}
