1	package alerts
2	
3	import "testing"
4	
5	func TestAlertLifecycleValidation(t *testing.T) {
6		// Test that resolution notes are required for close
7		if err := (Service{}).validateCloseNotes(""); err == nil {
8			t.Error("expected error when closing alert without resolution notes")
9		}
10		if err := (Service{}).validateCloseNotes("Fixed the issue by restocking"); err != nil {
11			t.Errorf("unexpected error: %v", err)
12		}
13	}
14	
15	func (s Service) validateCloseNotes(notes string) error {
16		if notes == "" {
17			return ErrResolutionRequired
18		}
19		return nil
20	}
21	
22	func TestAlertStatusTransitions(t *testing.T) {
23		// open -> claimed: valid
24		// open -> processing: invalid (must claim first)
25		// claimed -> processing: valid
26		// processing -> closed: valid (with notes)
27		// closed -> open: invalid
28	
29		validTransitions := map[string][]string{
30			"open":       {"claimed"},
31			"claimed":    {"processing"},
32			"processing": {"closed"},
33		}
34	
35		for from, tos := range validTransitions {
36			for _, to := range tos {
37				if !isValidAlertTransition(from, to) {
38					t.Errorf("expected valid transition from %q to %q", from, to)
39				}
40			}
41		}
42	
43		invalidTransitions := [][2]string{
44			{"open", "processing"},
45			{"open", "closed"},
46			{"claimed", "closed"},
47			{"closed", "open"},
48			{"processing", "open"},
49		}
50	
51		for _, tt := range invalidTransitions {
52			if isValidAlertTransition(tt[0], tt[1]) {
53				t.Errorf("expected invalid transition from %q to %q", tt[0], tt[1])
54			}
55		}
56	}
57	
58	func isValidAlertTransition(from, to string) bool {
59		allowed := map[string]string{
60			"open":       "claimed",
61			"claimed":    "processing",
62			"processing": "closed",
63		}
64		return allowed[from] == to
65	}
66	
