3	import (
4		"context"
5		"strings"
6		"testing"
7	)
8	
9	// TestTransitionOrderBlocksPaymentRecorded verifies the payment governance fix:
10	// the generic TransitionOrder MUST refuse payment_recorded transitions.
11	func TestTransitionOrderBlocksPaymentRecorded(t *testing.T) {
12		svc := &Service{}
13		err := svc.TransitionOrder(context.Background(), 1, StatusPaymentRecorded, nil, "user", "")
14		if err == nil {
15			t.Fatal("expected error when transitioning to payment_recorded via generic path")
16		}
17		if !strings.Contains(err.Error(), "dedicated payment-recorded endpoint") {
18			t.Errorf("error should mention dedicated endpoint, got: %v", err)
19		}
20	}
21	
22	// TestTransitionOrderDoesNotBlockOtherStates verifies that the payment guard
23	// only blocks payment_recorded and lets other transitions through.
24	func TestTransitionOrderDoesNotBlockOtherStates(t *testing.T) {
25		svc := &Service{}
26		// These will panic at DB access, but must NOT be caught by the payment guard
27		otherStates := []string{StatusCutoff, StatusCancelled, StatusPicking, StatusArrival}
28		for _, state := range otherStates {
29			t.Run(state, func(t *testing.T) {
30				var err error
31				func() {
32					defer func() { recover() }()
33					err = svc.TransitionOrder(context.Background(), 1, state, nil, "user", "")
34				}()
35				if err != nil && strings.Contains(err.Error(), "dedicated payment-recorded endpoint") {
36					t.Errorf("%s should not be blocked by payment guard", state)
37				}
38			})
39		}
40	}
41	
42	// TestBackorderLineStatuses verifies that the line status values used by the
43	// allocation logic are all valid against the domain model expectations.
44	func TestBackorderLineStatuses(t *testing.T) {
