	pool := testutil.MustDB(t)
	auditSvc := testutil.MustAudit(t, pool)
	svc := metrics.NewService(pool, auditSvc)
	ctx := context.Background()
	userID := testutil.SeedUser(t, pool, "Test User", "metric-filter@test.com")

