1	package alerts
2	
3	import (
4		"context"
5		"encoding/json"
6		"errors"
7		"fmt"
8		"time"
9	
10		"fleetcommerce/internal/audit"
11	
12		"github.com/jackc/pgx/v5/pgxpool"
13	)
14	
15	var (
16		ErrAlertNotOpen       = errors.New("alert is not in open state")
17		ErrAlertNotClaimed    = errors.New("alert is not claimed")
18		ErrAlertNotProcessing = errors.New("alert is not in processing state")
19		ErrResolutionRequired = errors.New("resolution notes are required to close an alert")
20	)
21	
22	type AlertRule struct {
23		ID          int             `json:"id"`
24		Name        string          `json:"name"`
25		Description string          `json:"description"`
26		RuleType    string          `json:"rule_type"`
27		Condition   json.RawMessage `json:"condition"`
28		Severity    string          `json:"severity"`
29		IsActive    bool            `json:"is_active"`
30	}
31	
32	type Alert struct {
33		ID              int        `json:"id"`
34		AlertRuleID     int        `json:"alert_rule_id"`
35		EntityType      string     `json:"entity_type"`
36		EntityID        int        `json:"entity_id"`
37		Status          string     `json:"status"`
38		Severity        string     `json:"severity"`
39		Title           string     `json:"title"`
40		Details         json.RawMessage `json:"details"`
41		ClaimedBy       *int       `json:"claimed_by"`
42		ClaimedByName   string     `json:"claimed_by_name"`
43		ClaimedAt       *time.Time `json:"claimed_at"`
44		ResolutionNotes string     `json:"resolution_notes"`
45		ClosedAt        *time.Time `json:"closed_at"`
46		CreatedAt       time.Time  `json:"created_at"`
47	}
48	
49	type Service struct {
50		pool     *pgxpool.Pool
51		auditSvc *audit.Service
52	}
53	
54	func NewService(pool *pgxpool.Pool, auditSvc *audit.Service) *Service {
55		return &Service{pool: pool, auditSvc: auditSvc}
56	}
57	
58	func (s *Service) ListAlerts(ctx context.Context, status string) ([]Alert, error) {
59		query := `SELECT a.id, a.alert_rule_id, a.entity_type, a.entity_id, a.status, a.severity, a.title,
60			a.details, a.claimed_by, COALESCE(u.full_name,''), a.claimed_at, a.resolution_notes, a.closed_at, a.created_at
61			FROM alerts a LEFT JOIN users u ON u.id = a.claimed_by`
62		var args []interface{}
63		if status != "" {
64			query += ` WHERE a.status = $1`
65			args = append(args, status)
66		}
67		query += ` ORDER BY a.created_at DESC`
68	
69		rows, err := s.pool.Query(ctx, query, args...)
70		if err != nil {
71			return nil, err
72		}
73		defer rows.Close()
74	
75		var alerts []Alert
76		for rows.Next() {
77			var a Alert
78			var resNotes *string
79			if err := rows.Scan(&a.ID, &a.AlertRuleID, &a.EntityType, &a.EntityID, &a.Status, &a.Severity, &a.Title,
80				&a.Details, &a.ClaimedBy, &a.ClaimedByName, &a.ClaimedAt, &resNotes, &a.ClosedAt, &a.CreatedAt); err != nil {
81				return nil, err
82			}
83			if resNotes != nil {
84				a.ResolutionNotes = *resNotes
85			}
86			alerts = append(alerts, a)
87		}
88		return alerts, nil
89	}
90	
91	func (s *Service) ClaimAlert(ctx context.Context, alertID, userID int) error {
92		var status string
93		err := s.pool.QueryRow(ctx, `SELECT status FROM alerts WHERE id=$1`, alertID).Scan(&status)
94		if err != nil {
95			return err
96		}
97		if status != "open" {
98			return ErrAlertNotOpen
99		}
100	
101		tx, err := s.pool.Begin(ctx)
102		if err != nil {
103			return err
104		}
105		defer tx.Rollback(ctx)
106	
107		if _, err := tx.Exec(ctx, `UPDATE alerts SET status='claimed', claimed_by=$1, claimed_at=NOW(), updated_at=NOW() WHERE id=$2`, userID, alertID); err != nil {
108			return fmt.Errorf("update alert status: %w", err)
109		}
110		if _, err := tx.Exec(ctx, `INSERT INTO alert_events (alert_id, event_type, from_status, to_status, actor_id) VALUES ($1,'claimed','open','claimed',$2)`, alertID, userID); err != nil {
111			return fmt.Errorf("insert alert event: %w", err)
112		}
113	
114		if err := s.auditSvc.LogTx(ctx, tx, audit.LogParams{
115			EntityType:  "alert",
116			EntityID:    alertID,
117			Action:      "claimed",
118			ActorUserID: &userID,
119			Before:      map[string]string{"status": "open"},
120			After:       map[string]string{"status": "claimed"},
121		}); err != nil {
122			return fmt.Errorf("write audit: %w", err)
123		}
124	
125		return tx.Commit(ctx)
126	}
127	
128	func (s *Service) ProcessAlert(ctx context.Context, alertID, userID int) error {
129		var status string
130		err := s.pool.QueryRow(ctx, `SELECT status FROM alerts WHERE id=$1`, alertID).Scan(&status)
131		if err != nil {
132			return err
133		}
134		if status != "claimed" {
135			return ErrAlertNotClaimed
136		}
137	
138		tx, err := s.pool.Begin(ctx)
139		if err != nil {
140			return err
141		}
142		defer tx.Rollback(ctx)
143	
144		if _, err := tx.Exec(ctx, `UPDATE alerts SET status='processing', updated_at=NOW() WHERE id=$1`, alertID); err != nil {
145			return fmt.Errorf("update alert status: %w", err)
146		}
147		if _, err := tx.Exec(ctx, `INSERT INTO alert_events (alert_id, event_type, from_status, to_status, actor_id) VALUES ($1,'processing','claimed','processing',$2)`, alertID, userID); err != nil {
148			return fmt.Errorf("insert alert event: %w", err)
149		}
150	
151		if err := s.auditSvc.LogTx(ctx, tx, audit.LogParams{
152			EntityType:  "alert",
153			EntityID:    alertID,
154			Action:      "processing",
155			ActorUserID: &userID,
156			Before:      map[string]string{"status": "claimed"},
157			After:       map[string]string{"status": "processing"},
158		}); err != nil {
159			return fmt.Errorf("write audit: %w", err)
160		}
161	
162		return tx.Commit(ctx)
163	}
164	
165	func (s *Service) CloseAlert(ctx context.Context, alertID, userID int, resolutionNotes string) error {
166		if resolutionNotes == "" {
167			return ErrResolutionRequired
168		}
169	
170		var status string
171		err := s.pool.QueryRow(ctx, `SELECT status FROM alerts WHERE id=$1`, alertID).Scan(&status)
172		if err != nil {
173			return err
174		}
175		if status != "processing" {
176			return ErrAlertNotProcessing
177		}
178	
179		tx, err := s.pool.Begin(ctx)
180		if err != nil {
181			return err
182		}
183		defer tx.Rollback(ctx)
184	
185		if _, err := tx.Exec(ctx, `UPDATE alerts SET status='closed', resolution_notes=$1, closed_at=NOW(), updated_at=NOW() WHERE id=$2`, resolutionNotes, alertID); err != nil {
186			return fmt.Errorf("update alert status: %w", err)
187		}
188		detailsJSON, _ := json.Marshal(map[string]string{"resolution_notes": resolutionNotes})
189		if _, err := tx.Exec(ctx, `INSERT INTO alert_events (alert_id, event_type, from_status, to_status, actor_id, details) VALUES ($1,'closed','processing','closed',$2,$3)`,
190			alertID, userID, detailsJSON); err != nil {
191			return fmt.Errorf("insert alert event: %w", err)
192		}
193	
194		if err := s.auditSvc.LogTx(ctx, tx, audit.LogParams{
195			EntityType:  "alert",
196			EntityID:    alertID,
197			Action:      "closed",
198			ActorUserID: &userID,
199			Before:      map[string]string{"status": "processing"},
200			After:       map[string]string{"status": "closed"},
201			Metadata:    map[string]string{"resolution_notes": resolutionNotes},
202		}); err != nil {
203			return fmt.Errorf("write audit: %w", err)
204		}
205	
206		return tx.Commit(ctx)
207	}
208	
209	// EvaluateAlerts checks all active rules and creates alerts as needed
210	func (s *Service) EvaluateAlerts(ctx context.Context) (int, error) {
211		rules, err := s.listActiveRules(ctx)
212		if err != nil {
213			return 0, err
214		}
215	
216		created := 0
217		for _, rule := range rules {
218			n, err := s.evaluateRule(ctx, rule)
219			if err != nil {
220				continue
221			}
222			created += n
223		}
224		return created, nil
225	}
226	
227	func (s *Service) listActiveRules(ctx context.Context) ([]AlertRule, error) {
228		rows, err := s.pool.Query(ctx, `SELECT id, name, description, rule_type, condition, severity, is_active FROM alert_rules WHERE is_active=TRUE`)
229		if err != nil {
230			return nil, err
231		}
232		defer rows.Close()
233	
234		var rules []AlertRule
235		for rows.Next() {
236			var r AlertRule
237			if err := rows.Scan(&r.ID, &r.Name, &r.Description, &r.RuleType, &r.Condition, &r.Severity, &r.IsActive); err != nil {
238				return nil, err
239			}
240			rules = append(rules, r)
241		}
242		return rules, nil
243	}
244	
245	func (s *Service) evaluateRule(ctx context.Context, rule AlertRule) (int, error) {
246		var cond struct {
247			Operator  string `json:"operator"`
248			Threshold int    `json:"threshold"`
249			Days      int    `json:"days"`
250		}
251		json.Unmarshal(rule.Condition, &cond)
252	
253		var query string
254		switch rule.RuleType {
255		case "low_stock":
256			query = `SELECT id, model_name, stock_quantity FROM vehicle_models WHERE publication_status='published' AND stock_quantity < $1`
257		case "overstock":
258			query = `SELECT id, model_name, stock_quantity FROM vehicle_models WHERE publication_status='published' AND stock_quantity > $1`
259		case "near_expiry":
260			query = `SELECT id, model_name, stock_quantity FROM vehicle_models WHERE publication_status='published' AND expiry_date IS NOT NULL AND expiry_date <= CURRENT_DATE + ($1 || ' days')::interval`
261		default:
262			return 0, nil
263		}
264	
265		rows, err := s.pool.Query(ctx, query, cond.Threshold)
266		if err != nil {
267			return 0, err
268		}
269		defer rows.Close()
270	
271		created := 0
272		for rows.Next() {
273			var modelID int
274			var modelName string
275			var stock int
276			if err := rows.Scan(&modelID, &modelName, &stock); err != nil {
