245	func (s *Service) ProcessExportRetries(ctx context.Context) (int, error) {
246		rows, err := s.pool.Query(ctx, `SELECT id, channel, recipient, subject, body, attempts, max_attempts FROM export_queue_items
247			WHERE status IN ('pending','retrying') AND attempts < max_attempts`)
248		if err != nil {
249			return 0, err
250		}
251		defer rows.Close()
252	
253		count := 0
254		for rows.Next() {
255			var item ExportQueueItem
256			if err := rows.Scan(&item.ID, &item.Channel, &item.Recipient, &item.Subject, &item.Body, &item.Attempts, &item.MaxAttempts); err != nil {
257				continue
258			}
259	
260			newAttempt := item.Attempts + 1
261	
262			// Write actual local artifact file
263			filename := fmt.Sprintf("export_%d_%s_%d.txt", item.ID, item.Channel, newAttempt)
264			exportPath := filepath.Join(s.exportsDir, filename)
265			payload := fmt.Sprintf("Channel: %s\nRecipient: %s\nSubject: %s\n\n%s", item.Channel, item.Recipient, item.Subject, item.Body)
266	
267			exportStatus := "exported"
268			if err := os.WriteFile(exportPath, []byte(payload), 0644); err != nil {
269				exportStatus = "retrying"
270				exportPath = ""
271			}
272	
273			if _, err := s.pool.Exec(ctx, `UPDATE export_queue_items SET status=$1, attempts=$2, last_attempt_at=NOW(), updated_at=NOW() WHERE id=$3`,
274				exportStatus, newAttempt, item.ID); err != nil {
275				return count, fmt.Errorf("update export queue item %d: %w", item.ID, err)
276			}
277			if _, err := s.pool.Exec(ctx, `INSERT INTO export_attempt_logs (queue_item_id, attempt_number, status, exported_path) VALUES ($1,$2,$3,$4)`,
278				item.ID, newAttempt, exportStatus, exportPath); err != nil {
279				return count, fmt.Errorf("insert export attempt log %d: %w", item.ID, err)
280			}
281			if exportStatus == "exported" {
282				count++
283			}
284		}
285		return count, nil
286	}
