288	// RenderTemplate performs simple variable substitution in templates
289	func (s *Service) RenderTemplate(ctx context.Context, templateCode string, vars map[string]string) (string, string, error) {
290		var tmpl Template
291		err := s.pool.QueryRow(ctx, `SELECT id, code, name, subject, body FROM notification_templates WHERE code=$1`, templateCode).
292			Scan(&tmpl.ID, &tmpl.Code, &tmpl.Name, &tmpl.Subject, &tmpl.Body)
293		if err != nil {
294			return "", "", err
295		}
296	
297		subject := tmpl.Subject
298		body := tmpl.Body
299		for k, v := range vars {
300			subject = strings.ReplaceAll(subject, "{{"+k+"}}", v)
301			body = strings.ReplaceAll(body, "{{"+k+"}}", v)
302		}
303	
304		return subject, body, nil
305	}
