131	// ListMetrics returns metrics filtered by metric-level permissions.
132	// Metrics with no rows in metric_permissions are visible to all with role-level access.
133	// Metrics with metric_permissions rows are only visible to permitted users.
134	func (s *Service) ListMetrics(ctx context.Context, userID int) ([]MetricDefinition, error) {
135		rows, err := s.pool.Query(ctx, `SELECT m.id, m.name, COALESCE(m.description,''), m.status, m.owner_id, COALESCE(u.full_name,''),
136			COALESCE((SELECT MAX(version_number) FROM metric_definition_versions WHERE metric_id=m.id), 0),
137			(SELECT COUNT(*) FROM metric_dependencies WHERE metric_id=m.id),
138			m.created_at
139			FROM metric_definitions m LEFT JOIN users u ON u.id = m.owner_id
140			WHERE NOT EXISTS (SELECT 1 FROM metric_permissions WHERE metric_id = m.id)
141			   OR EXISTS (SELECT 1 FROM metric_permissions mp WHERE mp.metric_id = m.id AND mp.can_view = TRUE
142			              AND (mp.user_id = $1 OR mp.role_id IN (SELECT role_id FROM user_roles WHERE user_id = $1)))
143			ORDER BY m.name`, userID)
