149		var metrics []MetricDefinition
150		for rows.Next() {
151			var m MetricDefinition
152			if err := rows.Scan(&m.ID, &m.Name, &m.Description, &m.Status, &m.OwnerID, &m.OwnerName, &m.LatestVersion, &m.DependencyCount, &m.CreatedAt); err != nil {
