174	func (s *Service) CreateMetric(ctx context.Context, p CreateParams) (int, error) {
175		tx, err := s.pool.Begin(ctx)
176		if err != nil {
177			return 0, err
178		}
179		defer tx.Rollback(ctx)
180	
181		var id int
182		err = tx.QueryRow(ctx, `INSERT INTO metric_definitions (name, description, owner_id) VALUES ($1,$2,$3) RETURNING id`,
183			p.Name, p.Description, p.OwnerID).Scan(&id)
184		if err != nil {
185			return 0, err
186		}
187	
188		if _, err := tx.Exec(ctx, `INSERT INTO metric_definition_versions (metric_id, version_number, sql_expression, semantic_formula, time_grain, is_derived, window_calculation, status)
189			VALUES ($1, 1, $2, $3, $4, $5, $6, 'draft')`, id, p.SQLExpression, p.SemanticFormula, p.TimeGrain, p.IsDerived, p.WindowCalculation); err != nil {
190			return 0, fmt.Errorf("create version: %w", err)
191		}
192	
193		// Persist dependencies
194		for _, depID := range p.DependsOnMetrics {
195			if _, err := tx.Exec(ctx, `INSERT INTO metric_dependencies (metric_id, depends_on_metric) VALUES ($1, $2)`, id, depID); err != nil {
196				return 0, fmt.Errorf("create dependency: %w", err)
197			}
198			// Also record lineage edge
199			if _, err := tx.Exec(ctx, `INSERT INTO metric_lineage_edges (source_type, source_id, target_type, target_id) VALUES ('metric', $1, 'metric', $2)`, depID, id); err != nil {
200				return 0, fmt.Errorf("create lineage edge: %w", err)
201			}
202		}
203	
204		// Persist filters
205		for _, f := range p.Filters {
206			if _, err := tx.Exec(ctx, `INSERT INTO metric_filters (metric_id, name, expression) VALUES ($1, $2, $3)`, id, f.Name, f.Expression); err != nil {
207				return 0, fmt.Errorf("create filter: %w", err)
208			}
209		}
210	
211		// Persist dimensions
212		for _, d := range p.Dimensions {
213			if _, err := tx.Exec(ctx, `INSERT INTO metric_dimensions (metric_id, name, description) VALUES ($1, $2, $3)`, id, d.Name, d.Description); err != nil {
214				return 0, fmt.Errorf("create dimension: %w", err)
215			}
216		}
217	
218		if err := s.auditSvc.LogTx(ctx, tx, audit.LogParams{
219			EntityType: "metric", EntityID: id, Action: "created", ActorUserID: &p.OwnerID,
220		}); err != nil {
221			return 0, fmt.Errorf("write audit: %w", err)
222		}
223	
224		return id, tx.Commit(ctx)
225	}
