227	// UpdateMetric creates a new version of the metric and replaces its dimensions, filters, and dependencies.
228	func (s *Service) UpdateMetric(ctx context.Context, p UpdateParams) error {
229		tx, err := s.pool.Begin(ctx)
230		if err != nil {
231			return err
232		}
233		defer tx.Rollback(ctx)
234	
235		// Get current latest version number
236		var latestVersion int
237		if err := tx.QueryRow(ctx, `SELECT COALESCE(MAX(version_number),0) FROM metric_definition_versions WHERE metric_id=$1`, p.MetricID).Scan(&latestVersion); err != nil {
238			return fmt.Errorf("get latest version: %w", err)
239		}
240		newVersion := latestVersion + 1
241	
242		// Update description on metric_definitions
243		if _, err := tx.Exec(ctx, `UPDATE metric_definitions SET description=$1, updated_at=NOW() WHERE id=$2`, p.Description, p.MetricID); err != nil {
244			return fmt.Errorf("update metric: %w", err)
245		}
246	
247		// Create new version
248		if _, err := tx.Exec(ctx, `INSERT INTO metric_definition_versions (metric_id, version_number, sql_expression, semantic_formula, time_grain, is_derived, window_calculation, status)
249			VALUES ($1, $2, $3, $4, $5, $6, $7, 'draft')`, p.MetricID, newVersion, p.SQLExpression, p.SemanticFormula, p.TimeGrain, p.IsDerived, p.WindowCalculation); err != nil {
250			return fmt.Errorf("create version: %w", err)
251		}
252	
253		// Replace dependencies
254		if _, err := tx.Exec(ctx, `DELETE FROM metric_dependencies WHERE metric_id=$1`, p.MetricID); err != nil {
255			return fmt.Errorf("clear dependencies: %w", err)
256		}
257		// Clear old lineage edges where this metric is the target
258		if _, err := tx.Exec(ctx, `DELETE FROM metric_lineage_edges WHERE target_type='metric' AND target_id=$1 AND source_type='metric'`, p.MetricID); err != nil {
259			return fmt.Errorf("clear lineage: %w", err)
260		}
261		for _, depID := range p.DependsOnMetrics {
262			if _, err := tx.Exec(ctx, `INSERT INTO metric_dependencies (metric_id, depends_on_metric) VALUES ($1, $2)`, p.MetricID, depID); err != nil {
263				return fmt.Errorf("create dependency: %w", err)
264			}
265			if _, err := tx.Exec(ctx, `INSERT INTO metric_lineage_edges (source_type, source_id, target_type, target_id) VALUES ('metric', $1, 'metric', $2)`, depID, p.MetricID); err != nil {
266				return fmt.Errorf("create lineage edge: %w", err)
267			}
268		}
269	
270		// Replace filters
271		if _, err := tx.Exec(ctx, `DELETE FROM metric_filters WHERE metric_id=$1`, p.MetricID); err != nil {
272			return fmt.Errorf("clear filters: %w", err)
273		}
274		for _, f := range p.Filters {
275			if _, err := tx.Exec(ctx, `INSERT INTO metric_filters (metric_id, name, expression) VALUES ($1, $2, $3)`, p.MetricID, f.Name, f.Expression); err != nil {
276				return fmt.Errorf("create filter: %w", err)
277			}
278		}
279	
280		// Replace dimensions
281		if _, err := tx.Exec(ctx, `DELETE FROM metric_dimensions WHERE metric_id=$1`, p.MetricID); err != nil {
282			return fmt.Errorf("clear dimensions: %w", err)
283		}
284		for _, d := range p.Dimensions {
285			if _, err := tx.Exec(ctx, `INSERT INTO metric_dimensions (metric_id, name, description) VALUES ($1, $2, $3)`, p.MetricID, d.Name, d.Description); err != nil {
286				return fmt.Errorf("create dimension: %w", err)
287			}
288		}
289	
290		if err := s.auditSvc.LogTx(ctx, tx, audit.LogParams{
291			EntityType: "metric", EntityID: p.MetricID, Action: "updated", ActorUserID: &p.ActorID,
292			Metadata: map[string]interface{}{"new_version": newVersion},
293		}); err != nil {
294			return fmt.Errorf("write audit: %w", err)
295		}
296	
297		return tx.Commit(ctx)
298	}
