400	func (s *Service) RunImpactAnalysis(ctx context.Context, metricID int) (*ImpactAnalysis, error) {
401		// Count dependent metrics
402		var depMetrics int
403		if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM metric_dependencies WHERE depends_on_metric=$1`, metricID).Scan(&depMetrics); err != nil {
404			return nil, fmt.Errorf("count dependent metrics: %w", err)
405		}
406	
407		// Count dependent charts
408		var depCharts int
409		if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM chart_metric_dependencies WHERE metric_id=$1`, metricID).Scan(&depCharts); err != nil {
410			return nil, fmt.Errorf("count dependent charts: %w", err)
411		}
412	
413		// Check for missing dependencies this metric needs
414		var missingDeps int
415		if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM metric_dependencies md
416			WHERE md.metric_id=$1 AND NOT EXISTS (SELECT 1 FROM metric_definitions WHERE id=md.depends_on_metric AND status='active')`,
417			metricID).Scan(&missingDeps); err != nil {
418			return nil, fmt.Errorf("count missing deps: %w", err)
419		}
420	
421		status := "approved"
422		if missingDeps > 0 {
423			status = "rejected"
424		}
425	
426		analysis := &ImpactAnalysis{
427			DependentMetrics: depMetrics,
428			DependentCharts:  depCharts,
429			MissingDeps:      missingDeps,
430			Status:           status,
431		}
432	
433		// Save review record
434		var latestVersionID int
435		if err := s.pool.QueryRow(ctx, `SELECT id FROM metric_definition_versions WHERE metric_id=$1 ORDER BY version_number DESC LIMIT 1`, metricID).Scan(&latestVersionID); err != nil {
436			return nil, fmt.Errorf("get latest version: %w", err)
437		}
438	
439		summary, err := json.Marshal(analysis)
440		if err != nil {
441			return nil, fmt.Errorf("marshal summary: %w", err)
442		}
443		if _, err := s.pool.Exec(ctx, `INSERT INTO metric_activation_reviews (metric_id, version_id, impact_summary, status) VALUES ($1,$2,$3,$4)`,
444			metricID, latestVersionID, summary, status); err != nil {
445			return nil, fmt.Errorf("save review: %w", err)
446		}
447	
448		return analysis, nil
449	}
