451	// CheckMetricPermission verifies that a user has access to a specific metric.
452	// Returns nil if access is allowed. Checks metric_permissions table first;
453	// if no rows exist for this metric, access falls through to role-level perms.
454	func (s *Service) CheckMetricPermission(ctx context.Context, metricID, userID int, needActivate bool) error {
455		// Check if metric-level permissions exist for this metric
456		var count int
457		if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM metric_permissions WHERE metric_id=$1`, metricID).Scan(&count); err != nil {
458			return fmt.Errorf("check metric permissions: %w", err)
459		}
460		if count == 0 {
461			return nil // no metric-level restrictions, fall through to role permission
462		}
463	
464		// Check user-level permission
465		query := `SELECT COUNT(*) FROM metric_permissions WHERE metric_id=$1 AND user_id=$2 AND can_view=TRUE`
466		if needActivate {
467			query = `SELECT COUNT(*) FROM metric_permissions WHERE metric_id=$1 AND user_id=$2 AND can_activate=TRUE`
468		}
469		var allowed int
470		if err := s.pool.QueryRow(ctx, query, metricID, userID).Scan(&allowed); err != nil {
471			return fmt.Errorf("check user permission: %w", err)
472		}
473		if allowed > 0 {
474			return nil
475		}
476	
477		// Check role-level permission
478		roleQuery := `SELECT COUNT(*) FROM metric_permissions mp
479			JOIN user_roles ur ON ur.role_id = mp.role_id
480			WHERE mp.metric_id=$1 AND ur.user_id=$2 AND mp.can_view=TRUE`
481		if needActivate {
482			roleQuery = `SELECT COUNT(*) FROM metric_permissions mp
483				JOIN user_roles ur ON ur.role_id = mp.role_id
484				WHERE mp.metric_id=$1 AND ur.user_id=$2 AND mp.can_activate=TRUE`
485		}
486		if err := s.pool.QueryRow(ctx, roleQuery, metricID, userID).Scan(&allowed); err != nil {
487			return fmt.Errorf("check role permission: %w", err)
488		}
489		if allowed > 0 {
490			return nil
491		}
492	
493		return errors.New("insufficient metric-level permissions")
494	}
495	
496	func (s *Service) ActivateMetric(ctx context.Context, metricID int, actorID int) error {
497		// Enforce metric-level permission
498		if err := s.CheckMetricPermission(ctx, metricID, actorID, true); err != nil {
499			return err
500		}
501	
502		// Get current state for audit before
503		metric, err := s.GetMetric(ctx, metricID)
504		if err != nil {
505			return err
506		}
507	
508		// Check last impact analysis was approved
509		var reviewStatus string
510		err = s.pool.QueryRow(ctx, `SELECT status FROM metric_activation_reviews WHERE metric_id=$1 ORDER BY created_at DESC LIMIT 1`, metricID).Scan(&reviewStatus)
511		if err != nil || reviewStatus != "approved" {
512			return ErrImpactAnalysisRequired
513		}
514	
515		// Check dependency chain: all depended-on metrics must be active
516		var missingDeps int
517		if err := s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM metric_dependencies md
518			WHERE md.metric_id=$1 AND NOT EXISTS (SELECT 1 FROM metric_definitions WHERE id=md.depends_on_metric AND status='active')`,
519			metricID).Scan(&missingDeps); err != nil {
520			return fmt.Errorf("check dependencies: %w", err)
521		}
522		if missingDeps > 0 {
523			return ErrMissingDependencies
524		}
525	
526		tx, err := s.pool.Begin(ctx)
527		if err != nil {
528			return err
529		}
530		defer tx.Rollback(ctx)
531	
532		if _, err := tx.Exec(ctx, `UPDATE metric_definitions SET status='active', updated_at=NOW() WHERE id=$1`, metricID); err != nil {
533			return fmt.Errorf("update status: %w", err)
534		}
535	
536		if err := s.auditSvc.LogTx(ctx, tx, audit.LogParams{
537			EntityType:  "metric",
538			EntityID:    metricID,
539			Action:      "activated",
540			ActorUserID: &actorID,
541			Before:      map[string]string{"status": metric.Status},
542			After:       map[string]string{"status": "active"},
543		}); err != nil {
544			return fmt.Errorf("write audit: %w", err)
545		}
546	
547		return tx.Commit(ctx)
548	}
