550	func (s *Service) GetLatestImpactAnalysis(ctx context.Context, metricID int) (*ImpactAnalysis, error) {
551		var summary json.RawMessage
552		var status string
553		err := s.pool.QueryRow(ctx, `SELECT impact_summary, status FROM metric_activation_reviews WHERE metric_id=$1 ORDER BY created_at DESC LIMIT 1`, metricID).Scan(&summary, &status)
554		if err != nil {
555			return nil, err
556		}
557	
558		var analysis ImpactAnalysis
