	count, err := svc.ProcessExportRetries(ctx)
	if err != nil {
		t.Fatalf("ProcessExportRetries: %v", err)
	}
	if count != 1 {
		t.Fatalf("expected 1 processed, got %d", count)
	}

	// Verify attempt log row
