func TestCreateParamsCarriesSemanticFields(t *testing.T) {
	p := CreateParams{
		Name:              "Test",
		IsDerived:         true,
		WindowCalculation: "7d_rolling_avg",
		DependsOnMetrics:  []int{1, 2},
		Filters: []MetricFilterDef{
